#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int freq[1001] = {0};
    for (int i = 0; i < n; i++) {
        int x;
        scanf("%d", &x);
        freq[x]++;
    }
    int pairs = 0;
    for (int i = 0; i <= 1000; i++) {
        pairs += freq[i] / 2;
    }
    printf("%d\n", pairs);
    return 0;
}

